+        assert!((corr - 1.0).abs() < 0.01);
+
+        let y_rev = vec![5, 4, 3, 2, 1];
+        let corr_rev = spearman_correlation(&x, &y_rev);
+        assert!((corr_rev + 1.0).abs() < 0.01);
+    }
