+#[test]
+fn test_tangent_cache_creation() {
+    let points = vec![
+        vec![0.1, 0.2, 0.1],
+        vec![-0.1, 0.15, 0.05],
+        vec![0.2, -0.1, 0.1],
+    ];
+    let indices: Vec<usize> = (0..3).collect();
+
+    let cache = TangentCache::new(&points, &indices, 1.0).unwrap();
+
